/// <summary>
/// Extension of the <c>PurchTable.PurchLine.InventRefTransId</c> form data source field for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataFieldStr(PurchTable, PurchLine, InventRefTransId))]
final class PurchTable_PurchLine_InventRefTransId_ETGSPAIN_FormDataSourceField_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>modified</c> method to update unsold quantity.
/// </summary>
void modified()
{
    next modified();

    FormDataObject  formDataObject  = any2Object(this) as FormDataObject;
    FormDataSource  formDataSource  = formDataObject.datasource();
    PurchLine       purchLine       = formDataSource.cursor();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (purchLine.InventRefTransId && purchLine.PurchQty)
        {
            ETGSPAINUnsoldInventTrans unsoldInventTrans = ETGSPAINUnsoldInventTrans::findByInventTransId(purchLine.InventRefTransId, true);

            if (unsoldInventTrans)
            {
                ETGSPAINUnsoldInventTransModifyController::updateQty(unsoldInventTrans, purchLine.PurchQty);
            }
        }
    }
}
